// Script: generar_59_editar_registro_diario.js
// Que hace: permite editar un registro diario ya guardado, en vez de
// solo bloquear la pantalla con "Ya registraste hoy".
//
//   1) app/registro-diario/page.tsx (REEMPLAZA el existente) -- si ya
//      existe un registro para la fecha indicada, la pantalla carga y
//      precarga TODAS las categorias, nota, y cuidados ya guardados
//      (reconstruidos desde las columnas de la base de datos), listos
//      para ajustar. El header muestra "· editando" junto a la fecha,
//      y el boton dice "Guardar cambios" en vez de "Guardar". El
//      guardado sigue usando upsert, asi que sobrescribe correctamente
//      sin crear filas duplicadas.
//
//   2) app/calendario/page.tsx (REEMPLAZA el existente) -- al tocar un
//      dia que YA tiene registro, ahora aparece un boton "✏️ Editar
//      este dia" debajo del resumen (antes solo se mostraba el resumen,
//      sin forma de editarlo). De paso se agregaron Heces y Paseo al
//      resumen visual, que faltaban desde que se crearon esas
//      categorias.
//
//   3) app/analisis/page.tsx (REEMPLAZA el existente) -- cada tarjeta
//      en "Registros recientes" ahora es clickeable y lleva directo a
//      editar ese dia especifico.
//
// Como correrlo: node generar_59_editar_registro_diario.js
// Confirma "OK" para los 3 archivos

const fs = require('fs');
const path = require('path');

function escribir(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const content = Buffer.from(b64, 'base64').toString('utf8');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, content, 'utf8');
  console.log('OK: ' + filePath);
}

escribir('app/registro-diario/page.tsx', "");
escribir('app/calendario/page.tsx', "");
escribir('app/analisis/page.tsx', "");
